import Image from "next/image";

// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";

// constants
const galleryItems = [
  {
    image: "https://cdn.uiable.com/block/g1.jpg",
    author: {
      name: "John Doe",
      title: "Manager at Apple",
      avatar: "https://cdn.uiable.com/block/user15.png",
    },
  },
  {
    image: "https://cdn.uiable.com/block/g2.jpg",
    author: {
      name: "John Doe",
      title: "Manager at Apple",
      avatar: "https://cdn.uiable.com/block/user14.png",
    },
  },
  {
    image: "https://cdn.uiable.com/block/g3.jpg",
    author: {
      name: "John Doe",
      title: "Manager at Apple",
      avatar: "https://cdn.uiable.com/block/user13.png",
    },
  },
  {
    image: "https://cdn.uiable.com/block/g4.jpg",
    author: {
      name: "John Doe",
      title: "Manager at Apple",
      avatar: "https://cdn.uiable.com/block/user1.png",
    },
  },
];

//  ------------------------------ | GALLERY 7 | ------------------------------  //

export default function Gallery6() {
  return (
    <section className="py-16 md:py-24">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-y-6">
          {/* Header Section */}
          <div className="col-span-12 text-center flex flex-col items-center gap-4">
            <h2>Best Shots</h2>
            <p className="text-slate-500 text-md md:text-lg max-w-2xl mb-12">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </p>
          </div>

          {/* Grid Section */}
          <div className="col-span-12">
            <div className="grid grid-cols-12 gap-x-6  max-w-5xl mx-auto gap-y-6">
              {galleryItems.map((item, index) => (
                <div
                  key={index}
                  className="col-span-12 md:col-span-6 flex flex-col gap-3"
                >
                  {/* Image Container */}
                  <div className="overflow-hidden rounded-2xl">
                    <div className="relative h-64">
                      <Image
                        src={item.image}
                        alt={`Gallery shot by ${item.author.name}`}
                        fill
                        className="object-cover"
                      />
                    </div>
                  </div>

                  {/* Author Attribution */}
                  <div className="flex items-center gap-3">
                    <Avatar className="h-14 w-14 border">
                      <AvatarImage
                        src={item.author.avatar}
                        alt={item.author.name}
                      />
                      <AvatarFallback>
                        {item.author.name.charAt(0)}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex flex-col gap-1">
                      <span className="text-lg font-semibold text-foreground">
                        {item.author.name}
                      </span>
                      <span className="text-md text-slate-500">
                        {item.author.title}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Call to Action Button */}
          <div className="col-span-12 flex justify-center mt-8">
            <Button size="lg">Get Started</Button>
          </div>
        </div>
      </div>
    </section>
  );
}
